import{_ as i,o as s,c as e,ag as l}from"./chunks/framework.uOkKsJ4G.js";const c=JSON.parse('{"title":"疑难排查","description":"Narrafiilm 常见问题的详细解决方案。","frontmatter":{"title":"疑难排查","description":"Narrafiilm 常见问题的详细解决方案。"},"headers":[],"relativePath":"guide/troubleshooting.md","filePath":"guide/troubleshooting.md","lastUpdated":1775970632000}'),t={name:"guide/troubleshooting.md"};function n(h,a,r,o,p,d){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="疑难排查" tabindex="-1">疑难排查 <a class="header-anchor" href="#疑难排查" aria-label="Permalink to &quot;疑难排查&quot;">​</a></h1><hr><h2 id="启动问题" tabindex="-1">启动问题 <a class="header-anchor" href="#启动问题" aria-label="Permalink to &quot;启动问题&quot;">​</a></h2><h3 id="应用启动无反应-windows" tabindex="-1">应用启动无反应（Windows） <a class="header-anchor" href="#应用启动无反应-windows" aria-label="Permalink to &quot;应用启动无反应（Windows）&quot;">​</a></h3><p>可能缺少 Visual C++ 运行库。</p><p><strong>解决方案</strong>：下载并安装 <a href="https://aka.ms/vs/17/release/vc_redist.x64.exe" target="_blank" rel="noreferrer">VC++ Redistributable</a>，然后重试。</p><hr><h3 id="应用启动无反应-linux-无头环境" tabindex="-1">应用启动无反应（Linux 无头环境） <a class="header-anchor" href="#应用启动无反应-linux-无头环境" aria-label="Permalink to &quot;应用启动无反应（Linux 无头环境）&quot;">​</a></h3><p>这是正常行为。Linux 服务器或 Docker 环境会自动切换到 <code>QT_QPA_PLATFORM=offscreen</code> 模式，不显示图形界面。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 手动指定无头模式</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> QT_QPA_PLATFORM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">offscreen</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app/main.py</span></span></code></pre></div><p>如果在没有显示器的桌面 Linux 上也无反应：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libegl1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libgl1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libxkbcommon0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libdbus-1-3</span></span></code></pre></div><hr><h2 id="ffmpeg-问题" tabindex="-1">FFmpeg 问题 <a class="header-anchor" href="#ffmpeg-问题" aria-label="Permalink to &quot;FFmpeg 问题&quot;">​</a></h2><h3 id="提示-ffmpeg-not-found" tabindex="-1">提示 &quot;FFmpeg not found&quot; <a class="header-anchor" href="#提示-ffmpeg-not-found" aria-label="Permalink to &quot;提示 &quot;FFmpeg not found&quot;&quot;">​</a></h3><p>FFmpeg 是核心依赖，未安装时所有视频操作失败。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># macOS</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ffmpeg</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ubuntu / Debian</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ffmpeg</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Windows</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 下载 https://www.gyan.dev/ffmpeg/builds/</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 解压后将 bin 目录加入 PATH，重启终端</span></span></code></pre></div><p>验证安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -version</span></span></code></pre></div><hr><h2 id="api-问题" tabindex="-1">API 问题 <a class="header-anchor" href="#api-问题" aria-label="Permalink to &quot;API 问题&quot;">​</a></h2><h3 id="_401-403-错误" tabindex="-1">401 / 403 错误 <a class="header-anchor" href="#_401-403-错误" aria-label="Permalink to &quot;401 / 403 错误&quot;">​</a></h3><p>API Key 无效、过期或账户额度用尽。</p><ol><li>登录 <a href="https://platform.deepseek.com" target="_blank" rel="noreferrer">platform.deepseek.com</a> 检查 Key 状态和余额</li><li>确认 Key 填写正确（注意没有多余空格）</li><li>重新复制 Key 粘贴到应用设置</li></ol><h3 id="_429-rate-limit" tabindex="-1">429 Rate Limit <a class="header-anchor" href="#_429-rate-limit" aria-label="Permalink to &quot;429 Rate Limit&quot;">​</a></h3><p>触发了 API 速率限制。等待 1 分钟重试，或在 DeepSeek 控制台查看配额。</p><h3 id="网络超时" tabindex="-1">网络超时 <a class="header-anchor" href="#网络超时" aria-label="Permalink to &quot;网络超时&quot;">​</a></h3><p>网络连接不稳定。检查：</p><ul><li>本机网络是否正常</li><li>API 服务是否可用（<a href="https://status.deepseek.com" target="_blank" rel="noreferrer">status.deepseek.com</a>）</li><li>是否有代理 / VPN 干扰</li></ul><hr><h2 id="视频处理问题" tabindex="-1">视频处理问题 <a class="header-anchor" href="#视频处理问题" aria-label="Permalink to &quot;视频处理问题&quot;">​</a></h2><h3 id="视频加载失败" tabindex="-1">视频加载失败 <a class="header-anchor" href="#视频加载失败" aria-label="Permalink to &quot;视频加载失败&quot;">​</a></h3><ul><li>确认文件格式受支持：MP4 / MOV / AVI / MKV / WebM</li><li>确认视频文件未损坏（用播放器打开测试）</li><li>确认磁盘空间充足（导出需要原片 2–3 倍空间）</li></ul><h3 id="处理到一半卡住" tabindex="-1">处理到一半卡住 <a class="header-anchor" href="#处理到一半卡住" aria-label="Permalink to &quot;处理到一半卡住&quot;">​</a></h3><ul><li>长视频（30 分钟+）建议分段处理</li><li>检查网络连接（API 调用需要网络）</li><li>查看应用日志（应用目录下的 <code>logs/</code> 文件夹）</li></ul><h3 id="显存不足-oom" tabindex="-1">显存不足（OOM） <a class="header-anchor" href="#显存不足-oom" aria-label="Permalink to &quot;显存不足（OOM）&quot;">​</a></h3><p>GPU 模式对显存要求高。关闭 GPU 加速：</p><p>设置 → AI 配置 → 启用 GPU 加速 → <strong>关闭</strong></p><p>或减少抽帧密度：设置 → 场景理解 → 抽帧间隔 → 2 秒</p><hr><h2 id="导出问题" tabindex="-1">导出问题 <a class="header-anchor" href="#导出问题" aria-label="Permalink to &quot;导出问题&quot;">​</a></h2><h3 id="导出失败" tabindex="-1">导出失败 <a class="header-anchor" href="#导出失败" aria-label="Permalink to &quot;导出失败&quot;">​</a></h3><ol><li>确认磁盘空间充足</li><li>检查输出目录是否有写入权限</li><li>临时关闭杀毒软件（部分杀软会拦截 FFmpeg）</li><li>尝试换用 H.264 编码（兼容性最好）</li></ol><h3 id="导出后视频无声音" tabindex="-1">导出后视频无声音 <a class="header-anchor" href="#导出后视频无声音" aria-label="Permalink to &quot;导出后视频无声音&quot;">​</a></h3><p>检查导出设置中 <strong>&quot;保留配音音轨&quot;</strong> 是否勾选。默认仅导出 AI 配音，原片音频需手动开启。</p><h3 id="剪映草稿无法导入" tabindex="-1">剪映草稿无法导入 <a class="header-anchor" href="#剪映草稿无法导入" aria-label="Permalink to &quot;剪映草稿无法导入&quot;">​</a></h3><ul><li>确认剪映版本为最新</li><li>草稿 JSON 需在剪映内通过&quot;导入草稿&quot;加载，不可直接双击</li><li>避免在包含中文字符的路径下保存草稿</li></ul><hr><h2 id="配音问题" tabindex="-1">配音问题 <a class="header-anchor" href="#配音问题" aria-label="Permalink to &quot;配音问题&quot;">​</a></h2><h3 id="edge-tts-无法连接" tabindex="-1">Edge-TTS 无法连接 <a class="header-anchor" href="#edge-tts-无法连接" aria-label="Permalink to &quot;Edge-TTS 无法连接&quot;">​</a></h3><ul><li>检查网络连接</li><li>确认可以访问 <code>edge.tts.azureedge.net</code></li><li>临时切换到 F5-TTS（完全本地，无需网络）</li></ul><h3 id="配音和字幕不同步" tabindex="-1">配音和字幕不同步 <a class="header-anchor" href="#配音和字幕不同步" aria-label="Permalink to &quot;配音和字幕不同步&quot;">​</a></h3><p>字幕同步依赖 TTS word-level timing，通常精度在 50ms 以内。明显不同步时：</p><ol><li>确认使用 Edge-TTS（非第三方 TTS）</li><li>检查解说稿是否有异常字符或特殊符号</li><li>在设置中开启 <strong>强制重新对齐</strong></li></ol><hr><h2 id="获取帮助" tabindex="-1">获取帮助 <a class="header-anchor" href="#获取帮助" aria-label="Permalink to &quot;获取帮助&quot;">​</a></h2><p>以上无法解决？去 <a href="https://github.com/Agions/Narrafiilm/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 搜索或新建 issue，并附上：</p><ul><li>Narrafiilm 版本（设置 → 关于）</li><li>操作系统版本</li><li>完整的错误日志（<code>logs/</code> 目录下）</li><li>复现步骤</li></ul>`,58)])])}const u=i(t,[["render",n]]);export{c as __pageData,u as default};
